OAuth implementations are frequently misconfigured, leading to account takeover and token theft. The 2022 GitHub/Heroku incident demonstrated how weak redirect URI validation and missing state parameter verification can be catastrophic.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const axios = require('axios');
const app = express();

const CLIENT_ID = process.env.OAUTH_CLIENT_ID;
const CLIENT_SECRET = process.env.OAUTH_CLIENT_SECRET;
const REDIRECT_URI = 'http://myapp.com/callback';

// VULNERABLE: No state parameter generated
app.get('/login', (req, res) => {
  const authUrl = `https://oauth.provider.com/authorize?` +
    `client_id=${CLIENT_ID}&` +
    `redirect_uri=${REDIRECT_URI}&` +
    `response_type=code&` +
    `scope=user:email`;
  res.redirect(authUrl);
});

// VULNERABLE: Multiple issues in callback handling
app.get('/callback', async (req, res) => {
  const { code, redirect_uri } = req.query;

  // VULNERABLE: Accepts redirect_uri from query params
  const callbackUrl = redirect_uri || REDIRECT_URI;

  // VULNERABLE: No state validation
  // VULNERABLE: No code validation
  const tokenResponse = await axios.post(
    'https://oauth.provider.com/token',
    {
      client_id: CLIENT_ID,
      client_secret: CLIENT_SECRET,
      code: code,
      redirect_uri: callbackUrl,
      grant_type: 'authorization_code'
    }
  );

  // VULNERABLE: Trusting user info without verification
  const userInfo = await axios.get(
    'https://oauth.provider.com/user',
    { headers: { Authorization: `Bearer ${tokenResponse.data.access_token}` }}
  );

  // VULNERABLE: Direct session creation without email verification
  req.session.user = userInfo.data;
  res.redirect('/dashboard');
});

app.listen(3000);
```

**Attack Payload - CSRF via Missing State Parameter**:
```html
<!-- Attacker hosts this on their site -->
<img src="https://myapp.com/callback?code=ATTACKER_AUTH_CODE" style="display:none">
<!-- When victim visits, their session links to attacker's OAuth account -->
```

**Attack Payload - Open Redirect Token Theft**:
```text
https://oauth.provider.com/authorize?
  client_id=VICTIM_CLIENT_ID&
  redirect_uri=https://attacker.com/steal&
  response_type=code&
  scope=user:email

# If redirect_uri validation is weak, authorization code goes to attacker
```

**Why This Is Dangerous**:
- **Missing state parameter**: Enables CSRF attacks where attacker can link victim's session to attacker's OAuth account
- **Accepting redirect_uri from query**: Allows attackers to redirect authorization codes to their server
- **No code validation**: Authorization codes can be replayed or stolen
- **Implicit trust in provider data**: Email from OAuth provider may not be verified

**SECURE VERSION**:

```javascript
const express = require('express');
const axios = require('axios');
const crypto = require('crypto');
const session = require('express-session');

const app = express();

app.use(session({
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: { secure: true, httpOnly: true, sameSite: 'lax' }
}));

const CLIENT_ID = process.env.OAUTH_CLIENT_ID;
const CLIENT_SECRET = process.env.OAUTH_CLIENT_SECRET;
// SECURE: Hardcoded, registered redirect URI
const REDIRECT_URI = 'https://myapp.com/callback';

// SECURE: Generate and store cryptographic state
app.get('/login', (req, res) => {
  const state = crypto.randomBytes(32).toString('hex');
  const nonce = crypto.randomBytes(32).toString('hex');

  // Store state in session for validation
  req.session.oauthState = state;
  req.session.oauthNonce = nonce;
  req.session.oauthTimestamp = Date.now();

  const authUrl = `https://oauth.provider.com/authorize?` +
    `client_id=${encodeURIComponent(CLIENT_ID)}&` +
    `redirect_uri=${encodeURIComponent(REDIRECT_URI)}&` +
    `response_type=code&` +
    `scope=user:email&` +
    `state=${encodeURIComponent(state)}&` +
    `nonce=${encodeURIComponent(nonce)}`;

  res.redirect(authUrl);
});

app.get('/callback', async (req, res) => {
  const { code, state, error } = req.query;

  // SECURE: Handle OAuth errors
  if (error) {
    console.error(`OAuth error: ${error}`);
    return res.status(400).redirect('/login?error=oauth_failed');
  }

  // SECURE: Validate state parameter against session
  if (!state || !req.session.oauthState || 
      !crypto.timingSafeEqual(
        Buffer.from(state), 
        Buffer.from(req.session.oauthState)
      )) {
    console.error('Invalid OAuth state parameter');
    return res.status(403).redirect('/login?error=invalid_state');
  }

  // SECURE: Check state expiration (5 minute window)
  if (Date.now() - req.session.oauthTimestamp > 300000) {
    console.error('OAuth state expired');
    return res.status(403).redirect('/login?error=state_expired');
  }

  // Clear OAuth state immediately after validation
  delete req.session.oauthState;
  delete req.session.oauthTimestamp;

  try {
    // SECURE: Use hardcoded redirect_uri, never from request
    const tokenResponse = await axios.post(
      'https://oauth.provider.com/token',
      new URLSearchParams({
        client_id: CLIENT_ID,
        client_secret: CLIENT_SECRET,
        code: code,
        redirect_uri: REDIRECT_URI,
        grant_type: 'authorization_code'
      }),
      { headers: { 'Content-Type': 'application/x-www-form-urlencoded' }}
    );

    // SECURE: Validate token response structure
    if (!tokenResponse.data.access_token) {
      throw new Error('No access token in response');
    }

    const userInfo = await axios.get(
      'https://oauth.provider.com/user',
      { headers: { Authorization: `Bearer ${tokenResponse.data.access_token}` }}
    );

    // SECURE: Verify email is confirmed by provider
    if (!userInfo.data.email_verified) {
      return res.status(403).redirect('/login?error=email_not_verified');
    }

    // Create session with validated user data
    req.session.regenerate((err) => {
      if (err) throw err;
      req.session.user = {
        id: userInfo.data.id,
        email: userInfo.data.email,
        provider: 'oauth_provider'
      };
      res.redirect('/dashboard');
    });

  } catch (error) {
    console.error('OAuth token exchange failed:', error.message);
    res.status(500).redirect('/login?error=server_error');
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Cryptographic state parameter**: 32-byte random value prevents CSRF attacks using timing-safe comparison
- **Hardcoded redirect_uri**: Never accept redirect URI from request parameters
- **State expiration**: 5-minute window prevents replay attacks with stolen states
- **Email verification check**: Ensures OAuth provider has verified the user's email
- **Session regeneration**: Prevents session fixation after authentication

Multi-provider OAuth with PKCE requires careful handling to prevent token confusion (CVE-2024-5217 in Okta), IdP mixup attacks, and code injection. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const axios = require('axios');
const crypto = require('crypto');
const session = require('express-session');
const { createClient } = require('redis');
const RedisStore = require('connect-redis').default;
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();

// Security headers
app.use(helmet());

// Redis for distributed session storage
const redisClient = createClient({ url: process.env.REDIS_URL });
redisClient.connect();

app.use(session({
  store: new RedisStore({ client: redisClient }),
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    sameSite: 'lax',
    maxAge: 3600000 // 1 hour
  }
}));

// Rate limiting for OAuth endpoints
const oauthLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 20, // 20 OAuth attempts per window
  message: 'Too many authentication attempts',
  standardHeaders: true
});

// Provider configurations - STRICTLY VALIDATED
const OAUTH_PROVIDERS = {
  google: {
    authUrl: 'https://accounts.google.com/o/oauth2/v2/auth',
    tokenUrl: 'https://oauth2.googleapis.com/token',
    userInfoUrl: 'https://www.googleapis.com/oauth2/v3/userinfo',
    clientId: process.env.GOOGLE_CLIENT_ID,
    clientSecret: process.env.GOOGLE_CLIENT_SECRET,
    scopes: ['openid', 'email', 'profile'],
    issuer: 'https://accounts.google.com',
    supportsPKCE: true
  },
  github: {
    authUrl: 'https://github.com/login/oauth/authorize',
    tokenUrl: 'https://github.com/login/oauth/access_token',
    userInfoUrl: 'https://api.github.com/user',
    emailUrl: 'https://api.github.com/user/emails',
    clientId: process.env.GITHUB_CLIENT_ID,
    clientSecret: process.env.GITHUB_CLIENT_SECRET,
    scopes: ['user:email'],
    issuer: 'https://github.com',
    supportsPKCE: false
  },
  microsoft: {
    authUrl: 'https://login.microsoftonline.com/common/oauth2/v2.0/authorize',
    tokenUrl: 'https://login.microsoftonline.com/common/oauth2/v2.0/token',
    userInfoUrl: 'https://graph.microsoft.com/v1.0/me',
    clientId: process.env.MICROSOFT_CLIENT_ID,
    clientSecret: process.env.MICROSOFT_CLIENT_SECRET,
    scopes: ['openid', 'email', 'profile'],
    issuer: 'https://login.microsoftonline.com',
    supportsPKCE: true
  }
};

// PKCE utilities
function generateCodeVerifier() {
  return crypto.randomBytes(32)
    .toString('base64url')
    .substring(0, 128);
}

function generateCodeChallenge(verifier) {
  return crypto
    .createHash('sha256')
    .update(verifier)
    .digest('base64url');
}

// Generate cryptographically secure state with embedded provider
function generateSecureState(provider) {
  const random = crypto.randomBytes(32).toString('hex');
  const timestamp = Date.now().toString(36);
  // Embed provider in state to prevent IdP mixup attacks
  const payload = JSON.stringify({ r: random, t: timestamp, p: provider });
  const signature = crypto
    .createHmac('sha256', process.env.STATE_SECRET)
    .update(payload)
    .digest('hex');
  return Buffer.from(`${payload}.${signature}`).toString('base64url');
}

// Validate state and extract provider
function validateSecureState(state) {
  try {
    const decoded = Buffer.from(state, 'base64url').toString();
    const [payload, signature] = decoded.split('.');

    const expectedSignature = crypto
      .createHmac('sha256', process.env.STATE_SECRET)
      .update(payload)
      .digest('hex');

    if (!crypto.timingSafeEqual(
      Buffer.from(signature), 
      Buffer.from(expectedSignature)
    )) {
      return null;
    }

    const data = JSON.parse(payload);
    const age = Date.now() - parseInt(data.t, 36);

    // State valid for 10 minutes
    if (age > 600000) {
      return null;
    }

    return data;
  } catch {
    return null;
  }
}

// Initiate OAuth flow
app.get('/auth/:provider', oauthLimiter, (req, res) => {
  const { provider } = req.params;
  const config = OAUTH_PROVIDERS[provider];

  // SECURE: Whitelist providers
  if (!config) {
    return res.status(400).json({ error: 'Invalid provider' });
  }

  const state = generateSecureState(provider);
  const nonce = crypto.randomBytes(32).toString('hex');

  // Store PKCE verifier if supported
  let codeVerifier = null;
  let codeChallenge = null;

  if (config.supportsPKCE) {
    codeVerifier = generateCodeVerifier();
    codeChallenge = generateCodeChallenge(codeVerifier);
  }

  // Store in session
  req.session.oauth = {
    state,
    nonce,
    provider,
    codeVerifier,
    initiatedAt: Date.now()
  };

  const redirectUri = `${process.env.APP_URL}/auth/${provider}/callback`;

  const params = new URLSearchParams({
    client_id: config.clientId,
    redirect_uri: redirectUri,
    response_type: 'code',
    scope: config.scopes.join(' '),
    state: state,
    nonce: nonce
  });

  // Add PKCE parameters
  if (config.supportsPKCE) {
    params.append('code_challenge', codeChallenge);
    params.append('code_challenge_method', 'S256');
  }

  console.log(`OAuth initiated: provider=${provider}, ip=${req.ip}`);
  res.redirect(`${config.authUrl}?${params.toString()}`);
});

// OAuth callback handler
app.get('/auth/:provider/callback', oauthLimiter, async (req, res) => {
  const { provider } = req.params;
  const { code, state, error, error_description } = req.query;
  const config = OAUTH_PROVIDERS[provider];

  // Audit logging
  const auditLog = (event, details) => {
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      event: `oauth_${event}`,
      provider,
      ip: req.ip,
      userAgent: req.get('user-agent'),
      ...details
    }));
  };

  // Handle OAuth errors from provider
  if (error) {
    auditLog('provider_error', { error, error_description });
    return res.redirect(`/login?error=${encodeURIComponent(error)}`);
  }

  // Validate provider
  if (!config) {
    auditLog('invalid_provider', {});
    return res.status(400).redirect('/login?error=invalid_provider');
  }

  // Validate session exists
  if (!req.session.oauth) {
    auditLog('missing_session', {});
    return res.status(403).redirect('/login?error=session_expired');
  }

  // CRITICAL: Validate state and embedded provider (prevents IdP mixup)
  const stateData = validateSecureState(state);
  if (!stateData) {
    auditLog('invalid_state', {});
    delete req.session.oauth;
    return res.status(403).redirect('/login?error=invalid_state');
  }

  // CRITICAL: Verify state matches session
  if (state !== req.session.oauth.state) {
    auditLog('state_mismatch', {});
    delete req.session.oauth;
    return res.status(403).redirect('/login?error=state_mismatch');
  }

  // CRITICAL: Verify provider in state matches URL (prevents token confusion)
  if (stateData.p !== provider || req.session.oauth.provider !== provider) {
    auditLog('provider_mismatch', { 
      expected: req.session.oauth.provider, 
      received: provider,
      inState: stateData.p 
    });
    delete req.session.oauth;
    return res.status(403).redirect('/login?error=provider_mismatch');
  }

  const { codeVerifier, nonce } = req.session.oauth;
  delete req.session.oauth; // Clear immediately

  try {
    const redirectUri = `${process.env.APP_URL}/auth/${provider}/callback`;

    // Build token request
    const tokenParams = {
      client_id: config.clientId,
      client_secret: config.clientSecret,
      code: code,
      redirect_uri: redirectUri,
      grant_type: 'authorization_code'
    };

    // Add PKCE verifier
    if (config.supportsPKCE && codeVerifier) {
      tokenParams.code_verifier = codeVerifier;
    }

    const tokenResponse = await axios.post(
      config.tokenUrl,
      new URLSearchParams(tokenParams),
      {
        headers: { 
          'Content-Type': 'application/x-www-form-urlencoded',
          'Accept': 'application/json'
        },
        timeout: 10000
      }
    );

    const { access_token, id_token, token_type } = tokenResponse.data;

    if (!access_token) {
      throw new Error('No access token received');
    }

    // Validate ID token if present (OpenID Connect)
    if (id_token) {
      const idTokenPayload = validateIdToken(id_token, config, nonce);
      if (!idTokenPayload) {
        throw new Error('Invalid ID token');
      }
    }

    // Fetch user info
    let userInfo;
    if (provider === 'github') {
      userInfo = await fetchGitHubUser(access_token, config);
    } else {
      const userResponse = await axios.get(config.userInfoUrl, {
        headers: { Authorization: `${token_type || 'Bearer'} ${access_token}` },
        timeout: 10000
      });
      userInfo = userResponse.data;
    }

    // SECURE: Verify email is confirmed
    if (!userInfo.email_verified && provider !== 'github') {
      auditLog('unverified_email', { email: userInfo.email });
      return res.redirect('/login?error=email_not_verified');
    }

    // Create user session with provider binding
    await new Promise((resolve, reject) => {
      req.session.regenerate((err) => {
        if (err) reject(err);
        else resolve();
      });
    });

    req.session.user = {
      id: `${provider}_${userInfo.sub || userInfo.id}`,
      email: userInfo.email,
      name: userInfo.name,
      provider: provider,
      providerUserId: userInfo.sub || userInfo.id,
      authenticatedAt: Date.now()
    };

    auditLog('login_success', { 
      userId: req.session.user.id,
      email: userInfo.email 
    });

    res.redirect('/dashboard');

  } catch (error) {
    auditLog('token_exchange_failed', { error: error.message });
    res.redirect('/login?error=authentication_failed');
  }
});

// GitHub-specific user fetch (needs separate email API call)
async function fetchGitHubUser(accessToken, config) {
  const [userResponse, emailResponse] = await Promise.all([
    axios.get(config.userInfoUrl, {
      headers: { Authorization: `Bearer ${accessToken}` },
      timeout: 10000
    }),
    axios.get(config.emailUrl, {
      headers: { Authorization: `Bearer ${accessToken}` },
      timeout: 10000
    })
  ]);

  const primaryEmail = emailResponse.data.find(e => e.primary && e.verified);
  if (!primaryEmail) {
    throw new Error('No verified primary email');
  }

  return {
    id: userResponse.data.id,
    email: primaryEmail.email,
    email_verified: true,
    name: userResponse.data.name || userResponse.data.login
  };
}

// Validate OpenID Connect ID token
function validateIdToken(idToken, config, expectedNonce) {
  try {
    const [headerB64, payloadB64] = idToken.split('.');
    const payload = JSON.parse(Buffer.from(payloadB64, 'base64url').toString());

    // Verify issuer
    if (!payload.iss || !payload.iss.startsWith(config.issuer)) {
      console.error('ID token issuer mismatch');
      return null;
    }

    // Verify audience
    const aud = Array.isArray(payload.aud) ? payload.aud : [payload.aud];
    if (!aud.includes(config.clientId)) {
      console.error('ID token audience mismatch');
      return null;
    }

    // Verify nonce (prevents replay)
    if (payload.nonce !== expectedNonce) {
      console.error('ID token nonce mismatch');
      return null;
    }

    // Verify expiration
    if (payload.exp * 1000 < Date.now()) {
      console.error('ID token expired');
      return null;
    }

    return payload;
  } catch (error) {
    console.error('ID token validation error:', error.message);
    return null;
  }
}

app.listen(3000);
```

**Defense in Depth Layers**:

1. **State Parameter with Embedded Provider**:
```javascript
// Prevents IdP mixup attacks - provider is cryptographically bound to state
const payload = JSON.stringify({ r: random, t: timestamp, p: provider });
const signature = crypto.createHmac('sha256', secret).update(payload).digest('hex');
// Verification checks both state validity AND provider match
```

2. **PKCE for Public/Mobile Clients**:
```javascript
// Code verifier never leaves the client until token exchange
const codeVerifier = crypto.randomBytes(32).toString('base64url');
const codeChallenge = crypto.createHash('sha256').update(codeVerifier).digest('base64url');
// Authorization code is useless without the verifier
```

3. **ID Token Validation (OpenID Connect)**:
```javascript
// Validates issuer, audience, nonce, and expiration
// Prevents token injection from different providers
if (!payload.iss.startsWith(config.issuer)) return null;
if (!aud.includes(config.clientId)) return null;
if (payload.nonce !== expectedNonce) return null;
```

**Additional Protections**:
- **Whitelist-only providers**: Enumerated providers prevent injection of malicious OAuth endpoints
- **Session regeneration**: Prevents session fixation after authentication completes
- **Comprehensive audit logging**: All OAuth events logged with IP, user agent, timestamps
- **Rate limiting**: 20 attempts per 15 minutes prevents brute force
- **Timeout on external requests**: 10-second timeout prevents hanging connections
- **Strict redirect URI**: Hardcoded, never from request parameters
- **Provider-specific handling**: GitHub's separate email API handled correctly
- **Redis session store**: Distributed sessions for horizontal scaling

Simply removing the user attribute or doing nothing with the session on logout is a critical security flaw. Sessions must be completely invalidated to prevent session hijacking attacks where an attacker who obtained a session token can continue using it even after the legitimate user logs out.

**VULNERABLE CODE**:

```java
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;

public class VulnerableLogoutServlet extends HttpServlet {

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        HttpSession session = request.getSession(false);

        if (session != null) {
            // VULNERABLE: Only removing user attribute, session still valid
            session.removeAttribute("user");
            session.removeAttribute("roles");

            // Session ID remains valid and can be reused!
        }

        // Redirect to login page
        response.sendRedirect("/login");
    }
}
```

**Attack Payload**:
```text
1. Attacker obtains session cookie: JSESSIONID=ABC123XYZ789
2. Legitimate user logs out (session not invalidated)
3. Attacker injects stolen cookie:
   Cookie: JSESSIONID=ABC123XYZ789
4. Attacker accesses protected resources using the still-valid session
```

**Why This Is Dangerous**:
- Session ID remains valid on the server after logout
- Attackers who captured the session token (via XSS, network sniffing, or physical access) can continue impersonating the user
- The session timeout clock doesn't reset, giving attackers the full remaining session lifetime
- Violates PCI-DSS requirement 8.1.8 and OWASP session management guidelines

**SECURE VERSION**:

```java
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import javax.servlet.http.Cookie;
import java.io.IOException;
import java.util.logging.Logger;

public class SecureLogoutServlet extends HttpServlet {

    private static final Logger logger = Logger.getLogger(SecureLogoutServlet.class.getName());

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        HttpSession session = request.getSession(false);

        if (session != null) {
            String username = (String) session.getAttribute("user");
            String sessionId = session.getId();

            // Log logout event for audit trail
            logger.info(String.format("User logout: %s, SessionID: %s, IP: %s", 
                username, sessionId, request.getRemoteAddr()));

            // SECURE: Completely invalidate the session
            session.invalidate();
        }

        // Clear the session cookie from client
        Cookie sessionCookie = new Cookie("JSESSIONID", null);
        sessionCookie.setPath(request.getContextPath());
        sessionCookie.setMaxAge(0);
        sessionCookie.setHttpOnly(true);
        sessionCookie.setSecure(true);
        response.addCookie(sessionCookie);

        // Prevent caching of authenticated pages
        response.setHeader("Cache-Control", "no-cache, no-store, must-revalidate");
        response.setHeader("Pragma", "no-cache");
        response.setHeader("Expires", "0");

        response.sendRedirect("/login?logout=success");
    }
}
```

**Key Security Controls**:
- **session.invalidate()**: Completely destroys the server-side session, making the session ID unusable
- **Cookie expiration**: Sets MaxAge=0 to instruct browser to delete the session cookie immediately
- **HttpOnly & Secure flags**: Prevents JavaScript access and ensures HTTPS-only transmission
- **Cache-Control headers**: Prevents browser from caching authenticated pages that could be accessed via back button

Excellent question! Production applications often have persistent remember-me tokens, refresh tokens, and users logged in from multiple devices. A comprehensive logout must handle all of these scenarios, including a "logout from all devices" feature.

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import javax.servlet.http.Cookie;
import java.io.IOException;
import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.SQLException;
import java.time.Instant;
import java.util.logging.Logger;
import javax.sql.DataSource;

public class ProductionLogoutServlet extends HttpServlet {

    private static final Logger logger = Logger.getLogger(ProductionLogoutServlet.class.getName());
    private static final String REMEMBER_ME_COOKIE = "REMEMBER_ME";
    private static final String REFRESH_TOKEN_COOKIE = "REFRESH_TOKEN";

    private DataSource dataSource;
    private SessionRegistry sessionRegistry;

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String logoutType = request.getParameter("type");
        boolean logoutAllDevices = "all".equals(logoutType);

        HttpSession session = request.getSession(false);
        String username = null;
        String currentSessionId = null;

        if (session != null) {
            username = (String) session.getAttribute("user");
            currentSessionId = session.getId();
        }

        try {
            if (logoutAllDevices && username != null) {
                // Invalidate ALL sessions for this user across all devices
                invalidateAllUserSessions(username, request.getRemoteAddr());
                // Revoke ALL remember-me tokens for this user
                revokeAllRememberMeTokens(username);
                // Revoke ALL refresh tokens
                revokeAllRefreshTokens(username);

                logger.info(String.format(
                    "SECURITY_AUDIT: Global logout for user=%s from IP=%s",
                    username, request.getRemoteAddr()));
