                // Revoke current device tokens only
                revokeRememberMeToken(request);
                revokeRefreshToken(request);

                logger.info(String.format(
                    "SECURITY_AUDIT: Single logout for user=%s sessionId=%s IP=%s",
                    username, currentSessionId, request.getRemoteAddr()));
