            // Clear all authentication cookies
            clearAuthenticationCookies(request, response);

            // Set security headers
            setSecurityHeaders(response);

            // Record logout in audit log
            recordAuditEvent(username, currentSessionId, 
                logoutAllDevices ? "GLOBAL_LOGOUT" : "SINGLE_LOGOUT",
                request.getRemoteAddr());

        } catch (Exception e) {
            logger.severe(String.format(
                "Logout error for user=%s: %s", username, e.getMessage()));
