    private void clearAuthenticationCookies(HttpServletRequest request, 
                                            HttpServletResponse response) {
        String[] cookiesToClear = {"JSESSIONID", REMEMBER_ME_COOKIE, REFRESH_TOKEN_COOKIE};

        for (String cookieName : cookiesToClear) {
            Cookie cookie = new Cookie(cookieName, null);
            cookie.setPath(request.getContextPath().isEmpty() ? "/" : request.getContextPath());
            cookie.setMaxAge(0);
            cookie.setHttpOnly(true);
            cookie.setSecure(true);
            response.addCookie(cookie);

            // Also clear for root path
            Cookie rootCookie = new Cookie(cookieName, null);
            rootCookie.setPath("/");
            rootCookie.setMaxAge(0);
            rootCookie.setHttpOnly(true);
            rootCookie.setSecure(true);
            response.addCookie(rootCookie);
        }
    }

