**Key Security Controls**:
- **Secrets in configuration**: Client secrets loaded from Azure Key Vault or environment variables, never hardcoded
- **Token validation**: Issuer, audience, signature, and expiration all validated
- **Reduced clock skew**: Limits token replay window to 1 minute instead of default 5
- **Required signed tokens**: Prevents 'alg:none' attacks where signature validation is bypassed

Implementing OAuth with PKCE (Proof Key for Code Exchange) and strict redirect URI validation is critical for production security. The 2023 OAuth redirect URI bypass attacks showed how loose validation patterns like regex matching can be exploited.

**PRODUCTION PATTERN**:

```csharp
using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Authentication.OpenIdConnect;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using Microsoft.IdentityModel.Protocols.OpenIdConnect;
using Microsoft.IdentityModel.Tokens;
using System;
using System.Collections.Generic;
using System.Security.Claims;
using System.Threading.Tasks;

namespace ProductionSecureOAuth
{
    public class Startup
    {
        private readonly IConfiguration _configuration;
        private readonly ILogger<Startup> _logger;

        public Startup(IConfiguration configuration, ILogger<Startup> logger)
        {
            _configuration = configuration;
            _logger = logger;
        }

        public void ConfigureServices(IServiceCollection services)
        {
            var oauthConfig = _configuration.GetSection("OAuth").Get<SecureOAuthConfig>();

            // SECURE: Register allowed redirect URIs (exact match only)
            services.AddSingleton<IRedirectUriValidator>(new StrictRedirectUriValidator(
                oauthConfig.AllowedRedirectUris
            ));

            services.AddAuthentication(options =>
            {
                options.DefaultScheme = "Cookies";
                options.DefaultChallengeScheme = "oidc";
            })
            .AddCookie("Cookies", options =>
            {
                options.Cookie.Name = "__Host-Session"; // SECURE: Host prefix
                options.Cookie.HttpOnly = true;
                options.Cookie.SecurePolicy = CookieSecurePolicy.Always;
                options.Cookie.SameSite = SameSiteMode.Strict;
                options.ExpireTimeSpan = TimeSpan.FromHours(1);
                options.SlidingExpiration = false; // SECURE: Fixed expiration
            })
            .AddOpenIdConnect("oidc", options =>
            {
                options.Authority = oauthConfig.Authority;
                options.ClientId = oauthConfig.ClientId;
                options.ClientSecret = oauthConfig.ClientSecret; // From Key Vault

                options.ResponseType = OpenIdConnectResponseType.Code;
                options.ResponseMode = OpenIdConnectResponseMode.Query;

                // SECURE: Enable PKCE
                options.UsePkce = true;

                // SECURE: Request minimal scopes
                options.Scope.Clear();
                options.Scope.Add("openid");
                options.Scope.Add("profile");
                options.Scope.Add("email");

                options.SaveTokens = true;
                options.GetClaimsFromUserInfoEndpoint = true;

                // SECURE: Strict redirect URI
                options.CallbackPath = new PathString("/signin-oidc");
                options.SignedOutCallbackPath = new PathString("/signout-callback-oidc");

                options.TokenValidationParameters = new TokenValidationParameters
                {
                    ValidateIssuer = true,
                    ValidateAudience = true,
                    ValidateLifetime = true,
                    ValidateIssuerSigningKey = true,
                    ValidIssuer = oauthConfig.Authority,
                    ValidAudiences = new[] { oauthConfig.ClientId },
                    ClockSkew = TimeSpan.FromSeconds(30),
                    RequireExpirationTime = true,
                    RequireSignedTokens = true,
                    NameClaimType = "name",
                    RoleClaimType = "roles"
                };

                options.Events = new OpenIdConnectEvents
                {
                    // SECURE: Validate state parameter
                    OnMessageReceived = context =>
                    {
                        if (string.IsNullOrEmpty(context.ProtocolMessage.State))
                        {
                            context.Fail("Missing state parameter - possible CSRF attack");
                            return Task.CompletedTask;
                        }
                        return Task.CompletedTask;
                    },

                    // SECURE: Additional redirect URI validation
                    OnRedirectToIdentityProvider = context =>
                    {
                        var validator = context.HttpContext.RequestServices
                            .GetRequiredService<IRedirectUriValidator>();

                        if (!validator.IsValidRedirectUri(context.ProtocolMessage.RedirectUri))
                        {
                            context.Response.StatusCode = 400;
                            context.HandleResponse();
                            return Task.CompletedTask;
                        }

                        // SECURE: Add nonce for replay protection
                        context.ProtocolMessage.Nonce = Guid.NewGuid().ToString();
                        return Task.CompletedTask;
                    },

                    OnTokenValidated = async context =>
                    {
                        var logger = context.HttpContext.RequestServices
                            .GetRequiredService<ILogger<Startup>>();

                        // SECURE: Validate token claims
                        var claims = context.Principal?.Claims;
                        var userId = context.Principal?.FindFirst(ClaimTypes.NameIdentifier)?.Value;

                        if (string.IsNullOrEmpty(userId))
                        {
                            context.Fail("Invalid token: missing subject claim");
                            return;
                        }

                        // SECURE: Audit logging
                        logger.LogInformation(
                            "OAuth login successful. UserId: {UserId}, IP: {IP}, UserAgent: {UA}",
                            userId,
                            context.HttpContext.Connection.RemoteIpAddress,
                            context.HttpContext.Request.Headers["User-Agent"].ToString()
                        );

                        await Task.CompletedTask;
                    },

                    OnAuthenticationFailed = context =>
                    {
                        var logger = context.HttpContext.RequestServices
                            .GetRequiredService<ILogger<Startup>>();

                        // SECURE: Log failures for monitoring
                        logger.LogWarning(
                            "OAuth authentication failed. Error: {Error}, IP: {IP}",
                            context.Exception?.Message,
                            context.HttpContext.Connection.RemoteIpAddress
                        );

                        // SECURE: Generic error message to user
                        context.Response.Redirect("/error?message=auth_failed");
                        context.HandleResponse();
                        return Task.CompletedTask;
                    },

                    OnRemoteFailure = context =>
                    {
                        var logger = context.HttpContext.RequestServices
                            .GetRequiredService<ILogger<Startup>>();

                        logger.LogError(
                            context.Failure,
                            "OAuth remote failure. IP: {IP}",
                            context.HttpContext.Connection.RemoteIpAddress
                        );

                        context.Response.Redirect("/error?message=provider_error");
                        context.HandleResponse();
                        return Task.CompletedTask;
                    }
                };
            });

            services.AddAuthorization(options =>
            {
                options.AddPolicy("RequireAuthenticatedUser", policy =>
                    policy.RequireAuthenticatedUser()
                          .RequireClaim(ClaimTypes.NameIdentifier));
            });
        }

        public void Configure(IApplicationBuilder app)
        {
            app.UseHttpsRedirection();
            app.UseHsts();

            // SECURE: Security headers
            app.Use(async (context, next) =>
            {
                context.Response.Headers.Add("X-Content-Type-Options", "nosniff");
                context.Response.Headers.Add("X-Frame-Options", "DENY");
                context.Response.Headers.Add("Referrer-Policy", "strict-origin-when-cross-origin");
                await next();
            });

            app.UseAuthentication();
            app.UseAuthorization();
        }
    }

    // SECURE: Strict redirect URI validator (exact match only)
    public interface IRedirectUriValidator
    {
        bool IsValidRedirectUri(string redirectUri);
    }

    public class StrictRedirectUriValidator : IRedirectUriValidator
    {
        private readonly HashSet<string> _allowedUris;

        public StrictRedirectUriValidator(IEnumerable<string> allowedUris)
        {
            // SECURE: Normalize and store allowed URIs
            _allowedUris = new HashSet<string>(
                allowedUris, 
                StringComparer.OrdinalIgnoreCase
            );
        }

        public bool IsValidRedirectUri(string redirectUri)
        {
            if (string.IsNullOrEmpty(redirectUri))
                return false;

            // SECURE: Parse and validate URI structure
            if (!Uri.TryCreate(redirectUri, UriKind.Absolute, out var uri))
                return false;

            // SECURE: Only allow HTTPS in production
            if (uri.Scheme != "https")
                return false;

            // SECURE: Exact match only - no wildcards, no regex
            var normalizedUri = $"{uri.Scheme}://{uri.Host}{uri.AbsolutePath}";
            return _allowedUris.Contains(normalizedUri);
        }
    }

    public class SecureOAuthConfig
    {
        public string Authority { get; set; }
        public string ClientId { get; set; }
        public string ClientSecret { get; set; }
        public List<string> AllowedRedirectUris { get; set; }
    }
}
```

**Defense in Depth Layers**:

1. **PKCE Protection**: Prevents authorization code interception attacks
```csharp
// PKCE generates code_verifier and code_challenge
options.UsePkce = true;
// Client sends code_verifier with token request
// Server validates SHA256(code_verifier) == code_challenge
```

2. **Strict Redirect URI Validation**: Exact match prevents open redirect attacks
```csharp
// NEVER use regex or wildcards for redirect URIs
// Vulnerable: /callback.* matches /callback.attacker.com
// Secure: Exact match only
_allowedUris.Contains(normalizedUri);
```

3. **State and Nonce Validation**: Prevents CSRF and replay attacks
```csharp
// State prevents CSRF during authorization
if (string.IsNullOrEmpty(context.ProtocolMessage.State))
    context.Fail("Missing state parameter");

// Nonce prevents token replay
context.ProtocolMessage.Nonce = Guid.NewGuid().ToString();
```

**Additional Protections**:
- **Token binding**: Consider implementing DPoP (Demonstrating Proof-of-Possession) for high-security scenarios
- **Short token lifetime**: Access tokens should expire in 5-15 minutes with refresh token rotation
- **Refresh token rotation**: Issue new refresh token on each use, invalidate old ones
- **Sender-constrained tokens**: Bind tokens to specific client certificates in mTLS environments
- **Monitoring**: Alert on unusual patterns like multiple failed authentications, token reuse attempts, or geographic anomalies

