Your logout implementation likely has a critical flaw - failing to properly invalidate server-side sessions allows attackers to reuse stolen session tokens even after users log out.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const session = require('express-session');

const app = express();

app.use(session({
  secret: 'mysecret',
  resave: false,
  saveUninitialized: false
}));

// Vulnerable logout - only clears client-side cookie
app.post('/logout', (req, res) => {
  // DANGEROUS: Only clears the cookie, session still exists on server!
  res.clearCookie('connect.sid');
  res.json({ message: 'Logged out successfully' });
});

// Another vulnerable pattern - just redirects without invalidation
app.get('/signout', (req, res) => {
  // DANGEROUS: Session data remains in session store
  req.session.user = null;
  res.redirect('/login');
});

app.get('/dashboard', (req, res) => {
  if (!req.session.user) {
    return res.status(401).json({ error: 'Not authenticated' });
  }
  res.json({ data: 'Sensitive dashboard data', user: req.session.user });
});
```

**Attack Scenario**:
```bash
# Attacker captures session cookie via XSS or network sniffing
# Session ID: s%3AaBC123...xyz

# User logs out through the vulnerable endpoint
curl -X POST http://example.com/logout -H "Cookie: connect.sid=s%3AaBC123...xyz"
# Response: {"message": "Logged out successfully"}

# Attacker uses stolen session - STILL WORKS!
curl http://example.com/dashboard -H "Cookie: connect.sid=s%3AaBC123...xyz"
# Response: {"data": "Sensitive dashboard data", "user": {...}}
```

**Why This Is Dangerous**:
- Session data persists in server-side store even after cookie is cleared
- Stolen session IDs remain valid indefinitely
- Setting `req.session.user = null` doesn't destroy the session object
- Attackers can replay captured sessions for hours, days, or longer

**SECURE VERSION**:

```javascript
const express = require('express');
const session = require('express-session');
const RedisStore = require('connect-redis').default;
const { createClient } = require('redis');

const app = express();

// Redis client for session store
const redisClient = createClient({ url: process.env.REDIS_URL });
redisClient.connect().catch(console.error);

app.use(session({
  store: new RedisStore({ client: redisClient }),
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    sameSite: 'strict',
    maxAge: 30 * 60 * 1000 // 30 minutes
  }
}));

// SECURE: Properly destroy server-side session
app.post('/logout', (req, res) => {
  const sessionId = req.session.id;
  const userId = req.session.user?.id;

  // Destroy the session completely on server
  req.session.destroy((err) => {
    if (err) {
      console.error(`Session destruction failed for user ${userId}:`, err);
      return res.status(500).json({ error: 'Logout failed' });
    }

    // Clear the session cookie on client
    res.clearCookie('connect.sid', {
      path: '/',
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict'
    });

    console.log(`User ${userId} logged out, session ${sessionId} destroyed`);
    res.json({ message: 'Logged out successfully' });
  });
});
```

**Key Security Controls**:
- `req.session.destroy()` removes session from server-side store completely
- Cookie cleared with same options as original cookie settings
- Session cannot be reused after destruction
- Audit logging captures logout events for security monitoring

Excellent question! Managing multi-device sessions requires tracking all sessions per user and implementing a "logout everywhere" feature. This is critical for security incidents where credentials may be compromised.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const session = require('express-session');
const RedisStore = require('connect-redis').default;
const { createClient } = require('redis');
const crypto = require('crypto');

const app = express();

const redisClient = createClient({ url: process.env.REDIS_URL });
redisClient.connect().catch(console.error);

// Custom session store with user-session tracking
class SecureSessionStore extends RedisStore {
  constructor(options) {
    super(options);
    this.client = options.client;
  }

  // Track session under user's session set
  async linkSessionToUser(sessionId, userId) {
    const key = `user_sessions:${userId}`;
    await this.client.sAdd(key, sessionId);
    // Set TTL matching session expiry
    await this.client.expire(key, 86400);
  }

  // Get all sessions for a user
  async getUserSessions(userId) {
    return await this.client.sMembers(`user_sessions:${userId}`);
  }

  // Remove session from user's set
  async unlinkSessionFromUser(sessionId, userId) {
    await this.client.sRem(`user_sessions:${userId}`, sessionId);
  }

  // Invalidate all sessions for a user
  async destroyAllUserSessions(userId) {
    const sessions = await this.getUserSessions(userId);
    const pipeline = this.client.multi();

    for (const sessionId of sessions) {
      pipeline.del(`sess:${sessionId}`);
    }
    pipeline.del(`user_sessions:${userId}`);

    await pipeline.exec();
    return sessions.length;
  }
}

const sessionStore = new SecureSessionStore({ client: redisClient });

app.use(session({
  store: sessionStore,
  secret: process.env.SESSION_SECRET,
  name: '__Host-sessionId', // Secure cookie prefix
  resave: false,
  saveUninitialized: false,
  genid: () => crypto.randomBytes(32).toString('hex'),
  cookie: {
    secure: true,
    httpOnly: true,
    sameSite: 'strict',
    maxAge: 30 * 60 * 1000,
    path: '/'
  }
}));

// Middleware to link sessions on login
const trackSession = async (req, res, next) => {
  if (req.session.user && !req.session.tracked) {
    await sessionStore.linkSessionToUser(
      req.session.id,
      req.session.user.id
    );
    req.session.tracked = true;
    req.session.deviceInfo = {
      userAgent: req.headers['user-agent'],
      ip: req.ip,
      createdAt: new Date().toISOString()
    };
  }
  next();
};

app.use(trackSession);

// Single device logout
app.post('/api/logout', async (req, res) => {
  const { id: sessionId } = req.session;
  const userId = req.session.user?.id;

  if (!userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  try {
    // Unlink from user's session set
    await sessionStore.unlinkSessionFromUser(sessionId, userId);

    // Destroy current session
    await new Promise((resolve, reject) => {
      req.session.destroy((err) => err ? reject(err) : resolve());
    });

    res.clearCookie('__Host-sessionId', {
      path: '/',
      secure: true,
      httpOnly: true,
      sameSite: 'strict'
    });

    // Audit log
    console.log(JSON.stringify({
      event: 'user_logout',
      userId,
      sessionId,
      timestamp: new Date().toISOString(),
      ip: req.ip
    }));

    res.json({ message: 'Logged out successfully' });
  } catch (error) {
    console.error('Logout error:', error);
    res.status(500).json({ error: 'Logout failed' });
  }
});

// Logout from all devices
app.post('/api/logout/all', async (req, res) => {
  const userId = req.session.user?.id;
  const currentSessionId = req.session.id;

  if (!userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  try {
    const destroyedCount = await sessionStore.destroyAllUserSessions(userId);

    res.clearCookie('__Host-sessionId', {
      path: '/',
      secure: true,
      httpOnly: true,
      sameSite: 'strict'
    });

    // Critical security audit log
    console.log(JSON.stringify({
      event: 'user_logout_all_devices',
      userId,
      sessionsDestroyed: destroyedCount,
      triggeredFrom: currentSessionId,
      timestamp: new Date().toISOString(),
      ip: req.ip
    }));

    res.json({ 
      message: 'Logged out from all devices',
      sessionsTerminated: destroyedCount
    });
  } catch (error) {
    console.error('Logout all error:', error);
    res.status(500).json({ error: 'Failed to logout from all devices' });
  }
});

// List active sessions for user
app.get('/api/sessions', async (req, res) => {
  const userId = req.session.user?.id;

  if (!userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  try {
    const sessionIds = await sessionStore.getUserSessions(userId);
    const sessions = [];

    for (const sid of sessionIds) {
      const data = await redisClient.get(`sess:${sid}`);
      if (data) {
        const parsed = JSON.parse(data);
        sessions.push({
          id: sid.substring(0, 8) + '...',
          deviceInfo: parsed.deviceInfo || {},
          isCurrent: sid === req.session.id
        });
      }
    }

    res.json({ sessions });
  } catch (error) {
    console.error('List sessions error:', error);
    res.status(500).json({ error: 'Failed to list sessions' });
  }
});

// Revoke specific session (e.g., from session management UI)
app.delete('/api/sessions/:sessionId', async (req, res) => {
  const userId = req.session.user?.id;
  const targetSession = req.params.sessionId;

  if (!userId) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  try {
    // Verify session belongs to this user
    const userSessions = await sessionStore.getUserSessions(userId);
    const fullSessionId = userSessions.find(s => s.startsWith(targetSession));

    if (!fullSessionId) {
      return res.status(404).json({ error: 'Session not found' });
    }

    // Don't allow revoking current session via this endpoint
    if (fullSessionId === req.session.id) {
      return res.status(400).json({ error: 'Use /logout to end current session' });
    }

    await redisClient.del(`sess:${fullSessionId}`);
    await sessionStore.unlinkSessionFromUser(fullSessionId, userId);

    console.log(JSON.stringify({
      event: 'session_revoked',
      userId,
      revokedSession: fullSessionId,
      revokedBy: req.session.id,
      timestamp: new Date().toISOString()
    }));

    res.json({ message: 'Session revoked' });
  } catch (error) {
    console.error('Revoke session error:', error);
    res.status(500).json({ error: 'Failed to revoke session' });
  }
});
```

**Defense in Depth Layers**:

1. **Session-User Binding**:
```javascript
// Track all sessions per user in Redis set
await redisClient.sAdd(`user_sessions:${userId}`, sessionId);
// Enables bulk invalidation without scanning all sessions
```

2. **Absolute Session Timeout**:
```javascript
// Force re-authentication after absolute time regardless of activity
app.use((req, res, next) => {
  if (req.session.user) {
    const created = new Date(req.session.createdAt).getTime();
    const maxAge = 24 * 60 * 60 * 1000; // 24 hours absolute

    if (Date.now() - created > maxAge) {
      return req.session.destroy(() => {
        res.status(401).json({ error: 'Session expired', code: 'SESSION_EXPIRED' });
      });
    }
  }
  next();
});
```

3. **Session Fingerprinting**:
```javascript
// Detect session hijacking via fingerprint mismatch
const validateSessionFingerprint = (req, res, next) => {
  if (req.session.user) {
    const currentFingerprint = crypto
      .createHash('sha256')
      .update(req.headers['user-agent'] || '')
      .digest('hex');

    if (req.session.fingerprint && req.session.fingerprint !== currentFingerprint) {
      console.warn(JSON.stringify({
        event: 'session_fingerprint_mismatch',
        userId: req.session.user.id,
        ip: req.ip
      }));
      return req.session.destroy(() => {
        res.status(401).json({ error: 'Session invalid' });
      });
    }
  }
  next();
};
```

**Additional Protections**:
- Use `__Host-` cookie prefix for enhanced cookie security (requires Secure, no Domain, Path=/)
- Implement session rotation on privilege changes (password change, role update)
- Send real-time notifications when new sessions are created
- Provide "Force logout" API for security incident response
- Consider short-lived sessions with refresh token rotation for high-security applications
